css:
.loader {
  position: relative;
  width: 150px;
  height: 150px;
  perspective: 900px;
  transform-style: preserve-3d;
}
.cube {
  position: absolute;
  top: 0;
  left: 0;
  width: 72px;
  height: 72px;
  transform-style: preserve-3d;
  transform: translateZ(-36px);
  animation: cubeRoute 4s cubic-bezier(.18,.56,.64,1) infinite;
}
.side {
  position: absolute;
  width: 72px;
  height: 72px;
  background: rgba(45, 96, 236, .82);
  border: 2px solid rgba(255,255,255,.55);
  box-shadow: inset 0 0 20px rgba(255,255,255,.18);
}
.side:nth-child(1) { transform: translateZ(36px); }
.side:nth-child(2) { transform: rotateY(180deg) translateZ(36px); }
.side:nth-child(3) { transform: rotateY(90deg) translateZ(36px); }
.side:nth-child(4) { transform: rotateY(-90deg) translateZ(36px); }
.side:nth-child(5) { transform: rotateX(90deg) translateZ(36px); }
.side:nth-child(6) { transform: rotateX(-90deg) translateZ(36px); }
@keyframes cubeRoute {
  0% { top: 0; left: 0; transform: translateZ(-36px); }
  25% { top: 78px; left: 78px; transform: translateZ(-36px) rotateX(-90deg) rotateZ(90deg); }
  50% { top: 0; left: 78px; transform: translateZ(-36px) rotateX(-180deg) rotateZ(180deg); }
  75% { top: 78px; left: 0; transform: translateZ(-36px) rotateX(-270deg) rotateZ(270deg); }
  100% { top: 0; left: 0; transform: translateZ(-36px) rotateX(-360deg) rotateZ(360deg); }
}
